  ('bookkeeper-moex-00515', 'bookkeeper', 'bookkeeper-moex-110-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '納稅義務人應納稅捐逾 30 日仍未繳納，應由稅捐稽徵機關移送強制執行，其依現行法可以暫緩強制執行 者，下列敘述何者錯誤？', '["已依稅捐稽徵法第35條規定申請復查者", "對於復查決定之應納稅額繳納三分之一，依法提起訴願者", "就應納稅額提供相當擔保，經稽徵機關核准者", "稽徵機關已就納稅義務人相當於復查決定應納稅額之財產，通知有關機關，不得為移轉或設定他項權利者"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:22+00:00", "source_pdf_sha1": "97bc6f66b10d", "answer_pdf_sha1": "a4bdb80f10ee", "source_family": "moex-gov-tw", "moex": {"exam_code": "110180", "c": "602", "s": "1204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "110", "exam_name": "110年專技人員高等考試建築師、24類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)、公共衛生師考試暨普通考試不動產...", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00516', 'bookkeeper', 'bookkeeper-moex-110-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '甲君因欠繳綜合所得稅導致其所有之土地遭法院拍賣，假設甲君尚未繳納或償還之項目包括：①欠繳之所', '["該筆土地的地價稅", "銀行抵押債務", "普通債務  則以上債權之清償順序應為下列何者？", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:22+00:00", "source_pdf_sha1": "97bc6f66b10d", "answer_pdf_sha1": "a4bdb80f10ee", "source_family": "moex-gov-tw", "moex": {"exam_code": "110180", "c": "602", "s": "1204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "110", "exam_name": "110年專技人員高等考試建築師、24類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)、公共衛生師考試暨普通考試不動產...", "original_question_number": 21, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
